SELECT count(*)
FROM hm_query.fact_returns fr
LEFT JOIN hm_query.dim_customer dc ON fr.customer_id = dc.customer_id
LEFT JOIN hm_query.dim_seller ds ON fr.seller_id = ds.seller_id
LEFT JOIN hm_query.dim_product dp ON fr.product_id = dp.product_id

    AND fr.order_id = #{orderId}
    AND fr.customer_id = #{customerId}
    AND fr.seller_id = #{sellerId}
    AND fr.product_id = #{productId}
    AND fr.state_id = #{stateId}
    AND fr.return_type = #{returnType}
    AND (
        fr.order_id LIKE CONCAT('%', #{q}, '%')
        OR dc.customer_name LIKE CONCAT('%', #{q}, '%')
        OR ds.seller_name LIKE CONCAT('%', #{q}, '%')
        OR dp.product_name LIKE CONCAT('%', #{q}, '%')
        OR fr.reason LIKE CONCAT('%', #{q}, '%')
    )

SELECT fr.id, fr.order_id as "orderId", fr.order_number as "orderNumber", fr.customer_id as "customerId", dc.customer_name as "customerName", dc.customer_email as "customerEmail", fr.seller_id as "sellerId", ds.seller_name as "sellerName", fr.product_id as "productId", dp.product_name as "productName", dp.sku as "productSku", fr.reason, fr.return_type as "returnType", fr.total_refund_amount as "totalRefundAmount", fr.order_total_value as "orderTotalValue", fr.state_id as "stateId", fr.flow_id as "flowId", fr.created_time as "createdTime" FROM hm_query.fact_returns fr LEFT JOIN hm_query.dim_customer dc ON fr.customer_id = dc.customer_id LEFT JOIN hm_query.dim_seller ds ON fr.seller_id = ds.seller_id LEFT JOIN hm_query.dim_product dp ON fr.product_id = dp.product_id
AND fr.order_id = #{orderId} AND fr.customer_id = #{customerId} AND fr.seller_id = #{sellerId} AND fr.product_id = #{productId} AND fr.state_id = #{stateId} AND fr.return_type = #{returnType} AND ( fr.order_id LIKE CONCAT('%', #{q}, '%') OR dc.customer_name LIKE CONCAT('%', #{q}, '%') OR ds.seller_name LIKE CONCAT('%', #{q}, '%') OR dp.product_name LIKE CONCAT('%', #{q}, '%') OR fr.reason LIKE CONCAT('%', #{q}, '%') )
${orderby} ${pagination}

SELECT count(*) FROM hm_query.fact_returns
WHERE seller_id = #{sellerId}
AND state_id = #{stateId}
